#include <bits/stdc++.h>
using namespace std;
const int N=1003;
struct Node{
    int dist,val;
};
int n,k,a[N],f[N][11],p[N][11],dep[N],ans;
vector<int> g[N];
void dfs(int x,int fa){
    dep[x]=dep[fa]+1;
    int len=g[x].size();
    for(int i=0;i<len;i++)
        if(g[x][i]!=fa){
            int v=g[x][i];
            p[v][0]=x,f[v][0]=a[x];
            for(int j=1;p[p[v][j-1]][j-1];j++){
                p[v][j]=p[p[v][j-1]][j-1];
                f[v][j]=f[v][j-1]+f[p[v][j-1]][j-1];
            }
            dfs(v,x);
        }
}
Node LCA(int x,int y){
    if(x==y)
        return {1,a[x]};
    if(dep[x]<dep[y])
        swap(x,y);
    int d=1,sum=a[x]+a[y];
    for(int i=10;i>=0;i--)
        if(dep[p[x][i]]>=dep[y])
            d+=1<<i,sum+=f[x][i],x=p[x][i];
    if(x==y)
        return {d,sum-a[x]};
    for(int i=10;i>=0;i--)
        if(p[x][i]!=p[y][i])
            d+=1<<i+1,sum+=f[x][i]+f[y][i],x=p[x][i],y=p[y][i];
    d+=2,sum+=f[x][0],x=p[x][0],y=p[y][0];
    return {d,sum};
}
int main(){
    scanf("%d%d",&n,&k);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    for(int i=1,u,v;i<n;i++){
        scanf("%d%d",&u,&v);
        g[u].push_back(v);
        g[v].push_back(u);
    }
    dfs(1,0);
    for(int i=1;i<=n;i++)
        for(int j=i;j<=n;j++){
            Node tmp=LCA(i,j);
            if(tmp.val<=k)
                ans=max(ans,tmp.dist);
        }
    printf("%d",ans);
    return 0;
}
